   281→            // and must meet the minimum threshold for dirty byte ratio or have some bytes required to be compacted
   282→            List<LogToClean> cleanableLogs = dirtyLogs.stream()
   283→                    .filter(ltc -> (ltc.needCompactionNow() && ltc.cleanableBytes() > 0) || ltc.cleanableRatio() > ltc.log().config().minCleanableRatio)
   284→                    .toList();
   285→
   286→            if (cleanableLogs.isEmpty()) {
   287→                return Optional.empty();
   288→            } else {
   289→                preCleanStats.recordCleanablePartitions(cleanableLogs.size());
   290→                LogToClean filthiest = cleanableLogs.stream()
   291→                        .max(Comparator.comparingDouble(LogToClean::cleanableRatio))
   292→                        .orElseThrow(() -> new IllegalStateException("No filthiest log found"));
   293→
   294→                inProgress.put(filthiest.topicPartition(), LogCleaningState.LOG_CLEANING_IN_PROGRESS);
   295→                return Optional.of(filthiest);
   296→            }
   297→        });
   298→    }
